package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Mamifero; public class Cachorro extends Mamifero implements Corrida, Predacao { public Cachorro(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " late: au au!"); } public void comer() { System.out.println(getNome() + " está comendo ração."); } public void correr() { System.out.println(getNome() + " está correndo pelo pátio."); } public void cacar() { System.out.println(getNome() + " está caçando a meia que roubou."); } }
